export const PURCHASE_TYPES = {
	GET_LIST_PURCHASE: 'GET_LIST_PURCHASE',
	SET_LIST_PURCHASE: 'SET_LIST_PURCHASE',
	CREATE: 'CREATE'
}

export function getListPurchase() {
	return {
		type: PURCHASE_TYPES.GET_LIST_PURCHASE
	}
}

export function setListPurchase(data: any) {
	return {
		type: PURCHASE_TYPES.SET_LIST_PURCHASE,
		payload: data
	}
}

export function create(data: any) {
	return {
		type: PURCHASE_TYPES.CREATE,
		payload: data
	}
}


