import { COMMON_TYPES } from './CommonAction'
import IAction from '../IAction';
export default class CommonReducer {

    private static readonly _initialState = {
        collapsed: true,
        access_token: '',
        configs: {},
        landingPageVideos: [],
        videoUrl: '',
        isShowLoading: false,
        listPackage: {},
        confirmSMS: {}
    };

    public static reducer(state = CommonReducer._initialState, action: IAction<any>) {
        switch (action.type) {
            case COMMON_TYPES.UPDATE_COLLAPSED:
              return {
                ...state,
                collapsed: action.payload 
              }
            case COMMON_TYPES.SET_CONFIG: {
              return {
                  ...state,
                  configs: action.payload
              }
            }
            case COMMON_TYPES.SET_VIDEO_ON_LANDING_PAGE: {
              return {
                ...state,
                landingPageVideos: action.payload
              }
            }
            case COMMON_TYPES.SET_VIDEO_URL: { 
              return {
                ...state,
                videoUrl: action.payload
              }
            }
            case COMMON_TYPES.SHOW_HIDE_LOADING: {
              return {
                ...state,
                isShowLoading: action.payload
              }
            }
            case COMMON_TYPES.SET_PACKAGE: {
              return {
                ...state,
                listPackage: action.payload
              }
            }
            case COMMON_TYPES.CONFIG_SMS: {
              return {
                ...state,
                confirmSMS: action.payload
              }
            }
            default:
              return state
          }
    }

}


