import { all, fork, takeLatest, select, put } from 'redux-saga/effects'
import { PURCHASE_TYPES } from '../stores/purchase/PurchaseAction';
import { _fetch, configs } from '../common';
import Base64 from 'crypto-js/enc-base64'
import hmacSHA1 from 'crypto-js/hmac-sha1';
import _ from 'lodash';
// import { notification } from 'antd'
import { setVideoOnLandingPage } from '../stores/common/CommonAction';
const getCommon= (state: any) => state.common;
function* create(action: any) {
	
	let payload = action.payload;
	let ctx = payload.ctx ? payload.ctx : {}
	let token;
	// let token = parseCookies(ctx)[configs.token] ? parseCookies(ctx)[configs.token] : '';
	let token_secret = ''
	if(token) {
		token_secret = JSON.parse(token).token_secret;
	}
	const res = yield _fetch(`${configs.baseURL}/api1/purchases/now`)
	let nonce = '';
	for(let i = 0; i < 6; i++) {
	  nonce +=	_.random(1, 9);
	}
	let _product = {
		product_id: payload.id,
		product_name: payload.name,
		product_type: payload.type,
		product_category: payload.category,
		rental_period: payload.rental_period ? payload.rental_period : 30,
		amount: payload.amount ? payload.amount : 29000,
		auto_renewal: payload.auto_renewal,
		ts: res.time,
		client_id: configs.clientId,
		nonce: nonce,
		hash: '',
		purchase_id: '',
		currency: 'VND',
      	normal: 0,
      	normal_vat: 0,
      	point: 0,
      	sale_code: configs.sale_code
	}
	let _hash = _product.client_id + _product.product_id + _product.ts + _product.nonce;
	_product.hash = encodeURIComponent(Base64.stringify(hmacSHA1(_hash, token_secret)));
	const _create = yield _fetch(`${configs.baseURL}/api1/purchases/create?hash=${_product.hash}&product_id=${_product.product_id}&product_name=${_product.product_name}
	&product_type=${_product.product_type}&product_category=${_product.product_category}&auto_renewal=${_product.auto_renewal}
	&ts=${_product.ts}&client_id=${_product.client_id}&nonce=${_product.nonce}&rental_period=${_product.rental_period}`, 'POST', _product, ctx)
	if(_create) 
		_product.purchase_id = _create.id;

	let payments = yield _fetch(`${configs.baseURL}/api1/payments/create?sale_code=${_product.sale_code}&currency=${_product.currency}&product_id=${_product.product_id}&product_name=${_product.product_name}
	&product_category=${_product.product_category}&product_type=${_product.product_type}&phone=${_product.amount}&purchase_id=${_product.purchase_id}`, 'POST', null, ctx)
	console.log("TCL: function*create -> payments", payments)
	if(payments && payments.id) {
		let stateCommon = yield select(getCommon);
		if(stateCommon.landingPageVideos && stateCommon.landingPageVideos.length > 0) {
			_.forEach(stateCommon.landingPageVideos, function(item) {
				item.isPurchased = true;
			})
			yield put (setVideoOnLandingPage(stateCommon.landingPageVideos))
		}
	} else if(payments.error && payments.error.code) {
		let _message = ''
        console.log("TCL: function*create -> _message", _message)
		switch (payments.error.code) {
            case 'U0252':
				_message = 'Tài khoản không đủ để đăng ký dịch vụ, Quý khách vui lòng kiểm tra và thử lại. Trân trọng';
              break;
            case 'U0232':
				_message = 'Tài khoản trong ví điện tử của bạn không đủ.';
              break;
            case 'U0503':
              _message = 'Không thể kết nối với máy chủ BMS. Vui lòng thử lại.';
              break;
            default:
              _message = 'Có lỗi trong quá trình thanh toán';
              break;
          }
		// notification.open({
		// 	message: 'Thông báo',
		// 	description: _message
		//   });
	}
}


function* actionWatcher() {
	yield takeLatest(PURCHASE_TYPES.CREATE , create)
}

export default function* purchaseSaga() {
	yield all([fork(actionWatcher)]);
}


