import React from 'react'

class VideoLandingPage extends React.Component<any, any> {
	render(): JSX.Element {
		return (
			<div>
				{ this.props.videos &&
					this.props.videos.map((item: any, index: any) => {
						if(index > 0) {
							return (
								<div className="item-video-ad" key={`video-ad-${index}`} onClick={() => {this.props.selectVideo(item, index)}}>
									<div className="image" style={{ backgroundImage: `url(${item.program.itemImage})`, backgroundSize: 'cover', backgroundPosition: 'center'}}>
										<div className="time">{item.program.display_runtime}</div>
									</div>
									<div className="description">
										<div className="name">{item.program.name}</div>
										<div className="like">{item.program.likes && (1000 + item.program.likes.total)} likes</div>
									</div>
								</div>
							)
						}
					})
				}
			</div>
		)
	}
}

export default VideoLandingPage;


