import { all, fork } from 'redux-saga/effects';
import authSaga from './auth';
import commonSaga from './common'
import purchaseSaga from './purchase'

export default function* rootSaga() {
  yield all([
    fork(authSaga),
    fork(commonSaga),
    fork(purchaseSaga)
  ])
}


