export const AUTH_TYPES = {
	LOGIN: 'LOGIN',
	SET_STATUS_LOGIN: 'SET_STATUS_LOGIN'
}

export interface IAccount {
	phone: string,
	password: string
}

export function login(auth: IAccount) {
	return {
		payload: auth,
		type: AUTH_TYPES.LOGIN,
	}
}

export function setStatusLogin(status: boolean) {
	return {
		payload: status,
		type: AUTH_TYPES.SET_STATUS_LOGIN
	}
}


