import React from 'react'
import Hls from 'hls.js'
// import { Icon } from 'antd'
import '../styles/hls-player.scss'
let hls : any;
let video: any;

interface IHLSProps {
	isShowBtnLandingPage: boolean,
	item: any,
	skipVideo?: () => void,
	buy?: () => void,
	url: string,
	isLogin: boolean
}

class HlsPlayer extends React.Component<IHLSProps, any> {
	constructor(props: IHLSProps) {
		super(props);
		this.state = {
			isShowPlayer: true,
			controls: false,
			muted: false,
			isPlaying: false
		}
	}
	componentDidMount() {
		this.initVideo();
	}

	initVideo(url?: string) {
		this.setState({
			isPlaying: false,
			controls: false
		})
		video = (document.getElementById('hls-video') as HTMLVideoElement);
		if(!url) url = this.props.url;
		if(Hls.isSupported()) {
			hls = new Hls();
			hls.loadSource(url);
			if(video !== null) {
				hls.attachMedia(video);
				this.addListenner();
			}
		}
	}

	componentWillReceiveProps(props: any) {
		if(this.props.url !== props.url) {
			this.initVideo(props.url);
		}
	}	
	addListenner() {
		hls.on(Hls.Events.MANIFEST_PARSED, ()=> {
		});
		hls.on(Hls.Events.ERROR, function () {
		})

		video.onplay = () => {
			if(!this.state.isPlaying) this.setState({ isPlaying: true })
		}
	}

	play() {
        console.log("TCL: HlsPlayer -> play -> play")
		if(this.props.isLogin) {
			this.setState({
				controls: true
			})
			video.play();
		}
	}

	render(): JSX.Element {
		return (
			<div className="hls-player">
				<div className="player" style={{ opacity: this.state.isShowPlayer ? '1' : '0'}}>
					<video  id="hls-video" muted={this.state.muted} controls={this.state.controls}>
						<source/>
					</video>
					<div className="background-hls-player" style={{ display: this.state.isPlaying ? 'none' : 'block', background: `url(${this.props.item && this.props.item.program.bigImage}) no-repeat center center / 100% 100%`}}></div>
					<div className="btn-skip" onClick={this.props.skipVideo} style={{ display:  this.props.isShowBtnLandingPage && this.props.item &&!this.props.item.program.isPurchased ? 'block' : 'none'}}></div>
					<div className="btn-register" onClick={this.props.buy} style={{ display:  this.props.isShowBtnLandingPage && this.props.item &&!this.props.item.program.isPurchased ? 'block' : 'none'}}>
						{/* <Icon type="play-circle" className="icon-pl" /> */}
						<div className="text">Đăng ký để xem video</div>
					</div>
					<div className="icon-play" style={{ display: this.props.item && this.props.item.program.isPurchased && !this.state.isPlaying ? 'block' : 'none'}} onClick={this.play.bind(this)}></div>
				</div>
				<div className="name">{this.props.item && this.props.item.program.name}</div>
				<div className="description" style={{ display: this.props.item && this.props.item.program.description ? 'block' : 'none' }}>{ this.props.item && this.props.item.program.description} </div>
			</div>

		)
	}
}

export default HlsPlayer


